async def run(args, state):
    content = state.get('content', '').lower()
    if 'заказ' in content or 'order' in content:
        state['route'] = 'order'
    elif 'жалоб' in content or 'complaint' in content:
        state['route'] = 'complaint'
    elif 'кот' in content or 'кошка' in content or 'cat' in content:
        state['route'] = 'cat'
    elif 'привет' in content or 'hello' in content:
        state['route'] = 'greeting'
    elif (
        'takeover' in content
        or 'перехват' in content
        or 'handover' in content
    ):
        state['route'] = 'takeover'
    elif (
        'оператор' in content
        or 'operator' in content
        or 'hitl' in content
        or 'human' in content
        or 'живой человек' in content
    ):
        state['route'] = 'operator'
    else:
        state['route'] = 'general'
    return state

