async function makeRouteNote(args, state) {
  const route = String(state.route ?? 'general');
  const note = String(args.note ?? `route:${route}`);
  state.graph_route_note = note;
  return {language: 'javascript', route, note};
}

async function buildEscalationHint(args: { severity?: number }, state: Record<string, unknown>) {
  const severity = Number(args.severity ?? 0);
  const needsOperator = severity >= 8;
  state.graph_needs_operator = needsOperator;
  return {language: 'typescript', severity, needs_operator: needsOperator};
}

