func NormalizeOrderReference(args map[string]any, state map[string]any) (any, error) {
    number := "unknown"
    if raw, ok := args["number"].(string); ok && raw != "" {
        number = raw
    }
    reference := "ORD-" + number
    state["graph_order_reference"] = reference
    return map[string]any{"language": "go", "reference": reference}, nil
}

using System.Collections.Generic;
using System.Threading.Tasks;

Task<object?> BuildFooter(Dictionary<string, object?> args, Dictionary<string, object?> state)
{
    var channel = args.TryGetValue("channel", out var raw) && raw is not null ? raw.ToString() : "chat";
    var footer = "Ответ подготовлен для " + channel;
    state["graph_reply_footer"] = footer;
    return Task.FromResult<object?>(new Dictionary<string, object?> { ["language"] = "csharp", ["footer"] = footer });
}
